#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        char s[1000005];
        scanf("%d", &N);
        scanf("%s", s);
        int len = strlen(s);
        char ans[1000005];
        int pos = 0;
        for (int i = 0; i < len; ++i) {
            if (i == 0 || s[i] != s[i-1]) {
                ans[pos++] = s[i];
            }
        }
        ans[pos] = '\0';
        printf("%s\n", ans);
    }
    return 0;
}

