#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))  # length, not needed
        u = next(it)
        # build result by taking first char of each run
        res = [u[0]]
        for ch in u[1:]:
            if ch != res[-1]:
                res.append(ch)
        out_lines.append(''.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

